import fs from "node:fs/promises";
import path from "node:path";
import { fileURLToPath } from "node:url";

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);
const repoRoot = path.resolve(__dirname, "..", "..");
const modulePath = path.join(repoRoot, "scripts", "data", "ninjutsu-definitions.module.mjs");
const classicPath = path.join(repoRoot, "scripts", "data", "ninjutsu-definitions.js");

const generatedBanner = [
  "// AUTO-GENERATED FILE.",
  "// Source: scripts/data/ninjutsu-definitions.module.mjs",
  "// Run: npm run sync:ninjutsu-definitions",
  "// Do not edit this file directly.",
  "",
].join("\n");

function toClassicSource(moduleSource) {
  const withoutExports = moduleSource.replace(/^export\s+/gm, "");
  return `${generatedBanner}${withoutExports}

globalThis.NindouNinjutsu = {
  catalog: ninjuCatalog,
  byType: ninjuByType,
  editorRowOrder: ninjuEditorRowOrder,
  editorCatalog: ninjuEditorCatalog,
  defaultLoadout: defaultNinjuLoadout,
};
`;
}

async function main() {
  const moduleSource = await fs.readFile(modulePath, "utf8");
  const classicSource = toClassicSource(moduleSource);
  await fs.writeFile(classicPath, classicSource, "utf8");
}

await main();
